diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index 255ce6973a16..0b64fb29017b 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -1538,6 +1538,24 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
   if (II->isCommutative()) {
     if (CallInst *NewCall = canonicalizeConstantArg0ToArg1(CI))
       return NewCall;
+    // For commutative intrinsics: if both first two operands are selects with
+    // the same condition and swapped arms, we can replace them directly.
+    // intrinsic(select(C, A, B), select(C, B, A), ...) -> intrinsic(B, A, ...)
+    Value *Cond, *A, *B;
+    if (match(II->getArgOperand(0),
+              m_Select(m_Value(Cond), m_Value(A), m_Value(B))) &&
+        match(II->getArgOperand(1),
+              m_Select(m_Specific(Cond), m_Specific(B), m_Specific(A)))) {
+      SmallVector<Value *, 4> NewArgs;
+      NewArgs.push_back(B);
+      NewArgs.push_back(A);
+      for (unsigned i = 2, e = II->arg_size(); i != e; ++i)
+        NewArgs.push_back(II->getArgOperand(i));
+      CallInst *NewCall =
+          Builder.CreateIntrinsic(II->getIntrinsicID(), II->getType(),
+                                  NewArgs, II);
+      return replaceInstUsesWith(CI, NewCall);
+    }
   }

   // Unused constrained FP intrinsic calls may have declared side effect, which
diff --git a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
index f072f5cec309..f7c9663fd7ea 100644
--- a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
@@ -1142,6 +1142,15 @@ Value *InstCombinerImpl::SimplifySelectsFeedingBinaryOp(BinaryOperator &I,
         True = Builder.CreateBinOp(Opcode, B, E);
       else if (True && !False)
         False = Builder.CreateBinOp(Opcode, C, F);
+      if (!True && !False && B == F && C == E &&
+          Instruction::isCommutative(Opcode)) {
+        // (A ? B : C) op (A ? C : B) -> B op C  (for commutative ops)
+        // Both arms produce the same value due to commutativity.
+        Value *NewBO = Builder.CreateBinOp(Opcode, B, C);
+        if (auto *NewBOI = dyn_cast<BinaryOperator>(NewBO))
+          NewBOI->copyIRFlags(&I);
+        return NewBO;
+      }
     }
   } else if (LHSIsSelect && LHS->hasOneUse()) {
